'use client';

import { useEffect } from 'react';
import { useAppDispatch, useAppSelector } from '@/store/hooks';
import { fetchSectionBySlug } from '@/store/slices/guideSlice';
import GuidePageLayout from '@/components/content/GuidePageLayout';

export default function GettingStartedPage() {
  const dispatch = useAppDispatch();
  const { currentSection, loading, error } = useAppSelector((s) => s.guide);

  useEffect(() => {
    dispatch(fetchSectionBySlug('getting-started'));
  }, [dispatch]);

  return <GuidePageLayout section={currentSection} loading={loading} error={error} />;
}
